// Normalize incoming payload from Neo Farmacia API webhook forward
const input = $input.first().json;
const body = input.body || input;

return [{
  json: {
    text: body.text || body.message || body.chatInput || '',
    storeId: body.storeId || 'store_leo',
    chatId: body.chatId || 'test-chat-' + Date.now(),
    phone: body.phone || '',
    pushName: body.pushName || 'Cliente'
  }
}];
